        // Cursor approaches within flee threshold (< 70 pixels for curious)
        context = BehaviorContext(
            creature: creature,
            screenBounds: context.screenBounds,
            currentTime: 0.7,
            cursorPosition: Position(x: state.position.x + 30, y: state.position.y)
        )
