            id: "climber-test",
            name: "Climber Test",
            personality: .curious,
            animations: [
                "climb": Animation(name: "climb", frameCount: 8, fps: 10),
                "idle": Animation(name: "idle", frameCount: 8, fps: 6)
            ]
        )
    }
}

